    .marca-dot { width: 6px; height: 6px; border-radius: 50%; background: #FF5500; flex-shrink: 0; }
    .marca-item span { font-family: 'Bebas Neue', sans-serif; font-size: 16px; letter-spacing: 2px; color: #f0ede8; }
    .descuento-cta { padding: 16px 18px; }
    .btn-orange { display: block; width: 100%; background: #FF5500; color: #fff; font-family: 'Bebas Neue', sans-serif; font-size: 15px; letter-spacing: 2px; padding: 14px; border: none; border-radius: 8px; cursor: pointer; text-align: center; }
